data.content:
MSTest **doesn't have** `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist. Here's what to use instead:

| Need | MSTest Approach |
|---|---|
| `value > x` | `Assert.IsTrue(value > x)` |
| `value >= x` | `Assert.IsTrue(value >= x)` |
| Range check | `Assert.IsTrue(value >= lo && value <= hi)` |
| Exact match | `Assert.AreEqual(expected, actual)` |
| Float tolerance | `Assert.AreEqual(expected, actual, delta)` |
| Exception | `Assert.ThrowsException<T>(action)` |

The `delta` overload of `Assert.AreEqual` is key for your `double` returns. Here's a complete test class:

```csharp
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // --- CalculatePercentage ---

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        Assert.AreEqual(100.0, _calc.CalculatePercentage(10, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_Returns0()
    {
        Assert.AreEqual(0.0, _calc.CalculatePercentage(0, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_Partial_ReturnsExpected()
    {
        Assert.AreEqual(75.0, _calc.CalculatePercentage(3, 4), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsInValidRange()
    {
        double result = _calc.CalculatePercentage(7, 10);
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Expected 0–100 but got {result}");
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(5, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [DataTestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.999, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.999, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.999, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.999, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(
        double percentage, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(percentage));
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        Assert.AreEqual(100.0, _calc.NormalizeScore(150, 100), 0.001);
    }

    [TestMethod]
    public void NormalizeScore_HalfMax_Returns50()
    {
        Assert.AreEqual(50.0, _calc.NormalizeScore(25, 50), 0.001);
    }

    [TestMethod]
    public void NormalizeScore_ResultNeverExceeds100()
    {
        double result = _calc.NormalizeScore(999, 10);
        Assert.IsTrue(result <= 100.0, $"Expected ≤100 but got {result}");
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(50, 0));
    }
}
```

**Key patterns used:**
- **`Assert.AreEqual(expected, actual, delta)`** — the `delta` (0.001) handles floating-point imprecision
- **`Assert.IsTrue(condition, message)`** — replaces the missing `IsGreaterThan`/`IsInRange`; always include a message so failures are diagnosable
- **`Assert.ThrowsException<T>`** — validates guard clauses
- **`[DataRow]` on boundaries** — the `89.999`/`90.0` pairs test both sides of each grade cutoff
